import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { useLanguage } from "./LanguageContext";
import LanguageToggle from "./LanguageToggle";

export default function AnimalDiseasePredictor() {
  const navigate = useNavigate();
  const { t } = useLanguage();
  const [animal, setAnimal] = useState("Cow");
  const [symptoms, setSymptoms] = useState({});
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const symptomList = [
    { key: "Fever", label: t('fever') },
    { key: "Mouth_Lesions", label: t('mouthLesions') },
    { key: "Lameness", label: t('lameness') },
    { key: "Milk_Drop", label: t('milkDrop') },
    { key: "Skin_Nodules", label: t('skinNodules') },
    { key: "Diarrhea", label: t('diarrhea') },
    { key: "Cough", label: t('cough') },
    { key: "Loss_Appetite", label: t('lossAppetite') }
  ];

  const handleCheckbox = (symptom) => {
    setSymptoms({
      ...symptoms,
      [symptom]: symptoms[symptom] ? 0 : 1
    });
  };

  const handleSubmit = async () => {
    setLoading(true);
    setResult(null);

    const payload = {
      Animal: animal,
      Fever: symptoms.Fever || 0,
      Mouth_Lesions: symptoms.Mouth_Lesions || 0,
      Lameness: symptoms.Lameness || 0,
      Milk_Drop: symptoms.Milk_Drop || 0,
      Skin_Nodules: symptoms.Skin_Nodules || 0,
      Diarrhea: symptoms.Diarrhea || 0,
      Cough: symptoms.Cough || 0,
      Loss_Appetite: symptoms.Loss_Appetite || 0
    };

    try {
      const res = await axios.post(
        "http://127.0.0.1:5000/predict-animal-disease",
        payload
      );
      setResult(res.data);
    } catch (err) {
      alert(t('serverError'));
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-orange-50 to-amber-100 py-10 px-4">
      <LanguageToggle />
      
      <div className="max-w-3xl mx-auto">
        {/* Back Button */}
        <button
          onClick={() => navigate('/')}
          className="mb-6 flex items-center text-orange-700 hover:text-orange-900 font-semibold transition-colors"
        >
          <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          {t('backHome')}
        </button>

        {/* Main Card */}
        <div className="bg-white rounded-3xl shadow-2xl overflow-hidden">
          {/* Header */}
          <div className="bg-gradient-to-r from-orange-500 to-amber-600 p-8 text-center">
            <div className="text-6xl mb-4">🐄</div>
            <h2 className="text-3xl font-bold text-white mb-2">
              {t('animalDiseaseTitle')}
            </h2>
            <p className="text-orange-100 text-lg">
              {t('animalPredictorDesc')}
            </p>
          </div>

          {/* Form */}
          <div className="p-8">
            {/* Animal Selection */}
            <div className="mb-8">
              <label className="block text-lg font-semibold text-gray-700 mb-4">
                {t('selectAnimal')}
              </label>
              <div className="grid grid-cols-3 gap-4">
                {[
                  { value: "Cow", label: t('cow'), emoji: "🐄" },
                  { value: "Goat", label: t('goat'), emoji: "🐐" },
                  { value: "Sheep", label: t('sheep'), emoji: "🐑" }
                ].map((item) => (
                  <button
                    key={item.value}
                    type="button"
                    onClick={() => setAnimal(item.value)}
                    className={`p-6 rounded-2xl border-3 font-bold text-lg transition-all duration-200 ${
                      animal === item.value
                        ? 'border-orange-500 bg-orange-50 text-orange-700 shadow-lg scale-105'
                        : 'border-gray-200 bg-white text-gray-600 hover:border-orange-300 hover:bg-orange-50'
                    }`}
                  >
                    <div className="text-4xl mb-2">{item.emoji}</div>
                    {item.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Symptoms Selection */}
            <div className="mb-8">
              <label className="block text-lg font-semibold text-gray-700 mb-4">
                {t('selectSymptoms')}
              </label>
              <div className="grid grid-cols-2 gap-4">
                {symptomList.map((symptom) => (
                  <label
                    key={symptom.key}
                    className={`flex items-center p-4 rounded-xl border-2 cursor-pointer transition-all duration-200 ${
                      symptoms[symptom.key]
                        ? 'border-orange-500 bg-orange-50 shadow-md'
                        : 'border-gray-200 bg-white hover:border-orange-300 hover:bg-orange-50'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={symptoms[symptom.key] === 1}
                      onChange={() => handleCheckbox(symptom.key)}
                      className="w-6 h-6 text-orange-600 rounded focus:ring-orange-500 focus:ring-2"
                    />
                    <span className={`ml-3 font-semibold text-lg ${
                      symptoms[symptom.key] ? 'text-orange-700' : 'text-gray-700'
                    }`}>
                      {symptom.label}
                    </span>
                  </label>
                ))}
              </div>
            </div>

            {/* Submit Button */}
            <button
              onClick={handleSubmit}
              disabled={loading}
              className={`w-full py-5 rounded-xl font-bold text-xl transition-all duration-300 ${
                loading
                  ? 'bg-gray-400 cursor-not-allowed'
                  : 'bg-gradient-to-r from-orange-500 to-amber-600 hover:from-orange-600 hover:to-amber-700 text-white shadow-lg hover:shadow-xl transform hover:scale-105'
              }`}
            >
              {loading ? (
                <span className="flex items-center justify-center">
                  <svg className="animate-spin h-6 w-6 mr-3" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  {t('predicting')}
                </span>
              ) : (
                t('predictDisease')
              )}
            </button>

            {/* Result Display */}
            {result && (
              <div className="mt-8 bg-gradient-to-br from-orange-400 to-amber-500 p-1 rounded-2xl">
                <div className="bg-white rounded-2xl p-6">
                  <div className="flex items-center mb-6">
                    <div className="w-14 h-14 bg-gradient-to-br from-orange-400 to-amber-500 rounded-full flex items-center justify-center mr-4 shadow-lg">
                      <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    </div>
                    <div>
                      <h3 className="text-2xl font-bold text-gray-900">
                        {t('detectionComplete')}
                      </h3>
                      <p className="text-gray-600">{t('analysisResults')}</p>
                    </div>
                  </div>

                  <div className="space-y-5">
                    {/* Disease */}
                    <div>
                      <h4 className="text-sm font-bold text-gray-600 mb-2 flex items-center uppercase tracking-wide">
                        <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                        </svg>
                        {t('disease')}
                      </h4>
                      <div className="bg-gradient-to-r from-orange-400 to-amber-500 text-white rounded-xl p-5 shadow-lg">
                        <p className="text-2xl font-bold">
                          {result.predicted_disease}
                        </p>
                      </div>
                    </div>

                    {/* Treatment */}
                    <div>
                      <h4 className="text-sm font-bold text-gray-600 mb-2 flex items-center uppercase tracking-wide">
                        <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                        </svg>
                        {t('treatment')}
                      </h4>
                      <div className="bg-gray-50 rounded-xl p-5 border-2 border-gray-200">
                        <p className="text-lg text-gray-800 leading-relaxed">
                          {result.treatment}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Info Footer */}
        <div className="mt-6 bg-white rounded-xl p-5 shadow-lg">
          <div className="flex items-start">
            <svg className="w-6 h-6 text-blue-500 mr-3 flex-shrink-0 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
            </svg>
            <div className="text-gray-700">
              <p className="font-semibold mb-1">Important Note</p>
              <p className="text-sm">Select all visible symptoms for accurate disease prediction. Consult a veterinarian for proper diagnosis and treatment.</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
